14	//
15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRC — crucible test cases for theurge end-to-end testing
18	//
19	// Cases execute inside a charged crucible (sentry + pentacle + bottle).
20	// Thread-local context bridges the static case function signature with
21	// the mutable invocation context needed for tabtarget calls.
22	
23	use std::cell::RefCell;
24	use std::io::Write;
25	use std::path::Path;
26	use std::process::{Command, Stdio};
27	
28	use crate::case;
29	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
30	use crate::rbtdri_invocation::{
31	    rbtdri_Context, rbtdri_invoke, rbtdri_invoke_global, rbtdri_invoke_imprint,
32	    rbtdri_parse_ifrit_verdict, rbtdri_read_burv_fact,
33	};
34	use crate::rbtdrm_manifest::{
35	    RBTDRM_COLOPHON_ABJURE, RBTDRM_COLOPHON_ACCESS_PROBE, RBTDRM_COLOPHON_BARK,
36	    RBTDRM_COLOPHON_FIAT, RBTDRM_COLOPHON_KLUDGE, RBTDRM_COLOPHON_ORDAIN,
37	    RBTDRM_COLOPHON_WREST, RBTDRM_COLOPHON_WRIT,
38	};
39	
40	// ── Thread-local invocation context ──────────────────────────
41	
42	/// Ifrit binary name inside the bottle container.
43	const RBTDRC_IFRIT_BINARY: &str = "rbid";
44	
45	/// Test connectivity target — ICANN-owned, stable single /20 CIDR (192.0.32.0/20)
46	const RBTDRC_CONNECTIVITY_DOMAIN: &str = "www.internic.net";
47	
48	thread_local! {
49	    static RBTDRC_CTX: RefCell<Option<rbtdri_Context>> = RefCell::new(None);
50	}
51	
52	/// Store invocation context for case functions. Called before run_sections.
53	pub fn rbtdrc_set_context(ctx: rbtdri_Context) {
54	    RBTDRC_CTX.with(|c| *c.borrow_mut() = Some(ctx));
55	}
56	
57	/// Retrieve invocation context after cases complete. Called for quench.
58	pub fn rbtdrc_take_context() -> rbtdri_Context {
59	    RBTDRC_CTX.with(|c| {
60	        c.borrow_mut()
61	            .take()
62	            .expect("rbtdrc: no context — was rbtdrc_set_context called?")
63	    })
64	}
65	
66	fn rbtdrc_with_ctx<F>(f: F) -> rbtdre_Verdict
67	where
68	    F: FnOnce(&mut rbtdri_Context) -> rbtdre_Verdict,
69	{
70	    RBTDRC_CTX.with(|c| {
71	        let mut opt = c.borrow_mut();
72	        let ctx = opt
73	            .as_mut()
74	            .expect("rbtdrc: no invocation context for case execution");
75	        f(ctx)
76	    })
77	}
78	
79	// ── Helpers ──────────────────────────────────────────────────
80	
81	/// Invoke ifrit inside the bottle via bark, saving stdout/stderr to case dir.
82	fn rbtdrc_invoke_ifrit(
83	    ctx: &mut rbtdri_Context,
84	    attack: &str,
85	    dir: &Path,
86	) -> rbtdre_Verdict {
87	    let result = match rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRC_IFRIT_BINARY, attack]) {
88	        Ok(r) => r,
89	        Err(e) => return rbtdre_Verdict::Fail(format!("bark invocation error: {}", e)),
90	    };
91	    let _ = std::fs::write(dir.join("bark-stdout.txt"), &result.stdout);
92	    let _ = std::fs::write(dir.join("bark-stderr.txt"), &result.stderr);
93	    rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code)
94	}
95	
96	/// Invoke ifrit inside the bottle via bark with extra arguments.
97	fn rbtdrc_invoke_ifrit_with_args(
98	    ctx: &mut rbtdri_Context,
99	    attack: &str,
100	    extra_args: &[&str],
101	    dir: &Path,
102	) -> rbtdre_Verdict {
103	    let mut bark_args = vec![RBTDRC_IFRIT_BINARY, attack];
104	    bark_args.extend_from_slice(extra_args);
105	    let result = match rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &bark_args) {
106	        Ok(r) => r,
107	        Err(e) => return rbtdre_Verdict::Fail(format!("bark invocation error: {}", e)),
108	    };
109	    let _ = std::fs::write(dir.join("bark-stdout.txt"), &result.stdout);
110	    let _ = std::fs::write(dir.join("bark-stderr.txt"), &result.stderr);
111	    rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code)
112	}
113	
114	/// Execute a command in the sentry via writ, returning captured stdout.
115	fn rbtdrc_writ(ctx: &mut rbtdri_Context, args: &[&str]) -> Result<String, String> {
116	    let result = rbtdri_invoke(ctx, RBTDRM_COLOPHON_WRIT, args)?;
117	    if result.exit_code != 0 {
118	        return Err(format!(
119	            "writ exit {}\nstdout: {}\nstderr: {}",
120	            result.exit_code, result.stdout, result.stderr
121	        ));
122	    }
123	    Ok(result.stdout)
124	}
125	
126	/// Execute a command in the pentacle via fiat, returning the invocation result.
127	fn rbtdrc_fiat(ctx: &mut rbtdri_Context, args: &[&str]) -> Result<String, String> {
128	    let result = rbtdri_invoke(ctx, RBTDRM_COLOPHON_FIAT, args)?;
129	    if result.exit_code != 0 {
130	        return Err(format!(
131	            "fiat exit {}\nstdout: {}\nstderr: {}",
132	            result.exit_code, result.stdout, result.stderr
133	        ));
134	    }
135	    Ok(result.stdout)
136	}
137	
138	/// Discover the sentry's enclave IP by reading /etc/resolv.conf from the pentacle via fiat.
139	/// The pentacle uses the sentry as its DNS server, so resolv.conf nameserver = sentry enclave IP.
140	/// (Sentry's own resolv.conf points to upstream DNS like 8.8.8.8 — wrong for enclave ops.)
141	fn rbtdrc_discover_sentry_ip(ctx: &mut rbtdri_Context) -> Result<String, String> {
142	    let output = rbtdrc_fiat(ctx, &["cat", "/etc/resolv.conf"])?;
143	    for line in output.lines() {
144	        let trimmed = line.trim();
145	        if let Some(rest) = trimmed.strip_prefix("nameserver") {
146	            let ip = rest.trim();
147	            if !ip.is_empty() && rbtdrc_looks_like_ip(ip) {
148	                return Ok(ip.to_string());
149	            }
150	        }
151	    }
152	    Err(format!(
153	        "no nameserver found in pentacle /etc/resolv.conf:\n{}",
154	        output
155	    ))
156	}
157	
158	/// Resolve a hostname via writ (running dig +short on the sentry).
159	/// Returns the first line that looks like an IP address (filters BUK log headers).
160	fn rbtdrc_resolve_via_writ(ctx: &mut rbtdri_Context, hostname: &str) -> Result<String, String> {
161	    let output = rbtdrc_writ(ctx, &["dig", "+short", hostname])?;
162	    let ip = output
163	        .lines()
164	        .find(|line| {
165	            let t = line.trim();
166	            !t.is_empty() && rbtdrc_looks_like_ip(t)
167	        })
168	        .map(|line| line.trim().to_string())
169	        .ok_or_else(|| format!("dig +short {} returned no IP:\n{}", hostname, output))?;
170	    Ok(ip)
171	}
172	
173	/// Quick check: does this string look like an IPv4 address (digits and dots only)?
